{
 "level": "A1–B1",
 "intro": "This section brings together topics that help you use <strong>nouns</strong>, <strong>articles</strong>, and <strong>quantity expressions</strong> correctly in English.",
 "rules": [
 {
 "label": "NOUNS",
 "color": "emerald",
 "text": "<strong>Noun forms</strong> — singular/plural, regular and irregular forms.",
 "example": "Plural Nouns, Irregular Plurals"
 },
 {
 "label": "ARTICLES",
 "color": "blue",
 "text": "<strong>Articles</strong> — a/an/the and the zero article.",
 "example": "Articles A / An / The"
 },
 {
 "label": "QUANTITY",
 "color": "amber",
 "text": "<strong>Quantity</strong> — some, any, much, many, few, little, a lot of.",
 "example": "Some / Any, Much / Many, Few / Little"
 }
 ]
}

{
 "title": "What belongs to this category",
 "intro": "The main subtopics logically grouped inside this category are:",
 "items": [
 {
 "label": "PLURAL",
 "title": "Plural nouns",
 "subtitle": "Rules for -s, -es, -ies, -ves, irregular plurals, singular-only and plural-only nouns."
 },
 {
 "label": "ARTICLES",
 "title": "Articles",
 "subtitle": "How to use a/an/the, the zero article, typical mistakes, and key exceptions."
 },
 {
 "label": "QUANTITY",
 "title": "Quantity",
 "subtitle": "Countable vs uncountable nouns, some/any, much/many, few/little, and related patterns."
 }
 ]
}

{
 "title": "When to open this section",
 "sections": [
 {
 "label": "Word form",
 "color": "emerald",
 "description": "Open this section when you need to decide which noun form to use: <strong>singular</strong> or <strong>plural</strong>.",
 "examples": [
 {
 "en": "one child / two children",
 "ua": "one child / two children"
 },
 {
 "en": "a box / three boxes",
 "ua": "a box / three boxes"
 }
 ]
 },
 {
 "label": "Article",
 "color": "blue",
 "description": "Open this section when you need to understand whether to use <strong>a/an/the</strong> or leave the noun without an article.",
 "examples": [
 {
 "en": "a book",
 "ua": "a book"
 },
 {
 "en": "the book",
 "ua": "the book"
 }
 ]
 },
 {
 "label": "Quantity",
 "color": "amber",
 "description": "Open this section when you need to choose a quantity word such as <strong>some, any, much, many, few, little</strong>.",
 "examples": [
 {
 "en": "many books",
 "ua": "many books"
 },
 {
 "en": "little water",
 "ua": "little water"
 }
 ]
 }
 ]
}

{
 "title": "Keep learning",
 "items": [
